-- Idempotent migration: HVAC checkpoint quiz_questions
-- Generated from live DB. Re-run safely at any time.
-- Matches on program_id + lesson_slug — no UUID dependency.

DO $$
DECLARE
  prog_id uuid := '4226f7f6-fbc1-44b5-83e8-b12ea149e4c7';
BEGIN

  -- hvac-lesson-14: Electrical Basics Quiz (10q)
  UPDATE curriculum_lessons
    SET quiz_questions = '[{"id":"eb1-1","options":["V = I + R","V = I × R","I = V + R","R = V + I"],"question":"State Ohm''s Law.","explanation":"Ohm''s Law: V = I × R. Voltage drives current through resistance.","correctAnswer":1},{"id":"eb1-2","options":["Volt","Ampere","Ohm","Watt"],"question":"What unit measures electrical resistance?","explanation":"Resistance is measured in Ohms (Ω). It opposes the flow of current in a circuit.","correctAnswer":2},{"id":"eb1-3","options":["Measures voltage","Stores electrical energy and provides a starting boost to motors","Protects against short circuits","Regulates refrigerant flow"],"question":"What does a capacitor do in an HVAC system?","explanation":"Capacitors store electrical energy and provide the phase shift needed to start and run single-phase motors.","correctAnswer":1},{"id":"eb1-4","options":["Measures current draw","Acts as a high-voltage switch controlled by a low-voltage signal","Filters electrical noise","Stores energy for motor starting"],"question":"What is the function of a contactor in an HVAC system?","explanation":"A contactor is an electrically controlled switch. Low-voltage thermostat signal energizes the coil, closing high-voltage contacts to the compressor and condenser fan.","correctAnswer":1},{"id":"eb1-5","options":["Manifold gauge set","Micron gauge","Multimeter","Clamp meter"],"question":"What tool measures voltage, current, and resistance in HVAC circuits?","explanation":"A multimeter measures voltage (V), current (A), and resistance (Ω) — the primary electrical diagnostic tool.","correctAnswer":2},{"id":"eb1-6","options":["Series has one current path; parallel has multiple paths","Parallel has one current path; series has multiple paths","Series has higher voltage; parallel has lower voltage","There is no practical difference"],"question":"What is the difference between a series and parallel circuit?","explanation":"Series: one path — one failure opens the whole circuit. Parallel: multiple paths — one failure does not stop current to others.","correctAnswer":0},{"id":"eb1-7","options":["Physical location of components","Electrical connections and circuit logic between components","Refrigerant flow path","Duct layout"],"question":"What does a wiring diagram show that a pictorial diagram does not?","explanation":"Wiring (schematic) diagrams show circuit logic. Pictorial diagrams show physical appearance and location.","correctAnswer":1},{"id":"eb1-8","options":["Measure resistance","Use a low-voltage signal to switch a higher-voltage circuit","Store energy for motor starting","Protect against overcurrent"],"question":"What is the purpose of a relay in an HVAC control circuit?","explanation":"A relay uses a small control voltage to open or close contacts in a higher-voltage circuit, similar to a contactor but for lighter loads.","correctAnswer":1},{"id":"eb1-9","options":["Voltage","Resistance","AC current without breaking the circuit","Capacitance"],"question":"What does a clamp meter measure that a standard multimeter cannot?","explanation":"A clamp meter measures AC current by clamping around a single conductor — no need to break the circuit.","correctAnswer":2},{"id":"eb1-10","options":["120V AC","240V AC","24V AC","12V DC"],"question":"What is the typical low-voltage control circuit voltage in residential HVAC?","explanation":"Residential HVAC control circuits operate at 24V AC from a step-down transformer, controlling contactors, relays, and the thermostat circuit.","correctAnswer":2}]'::jsonb
    WHERE program_id = prog_id AND lesson_slug = 'hvac-lesson-14';

  -- hvac-lesson-20: Heating Systems Quiz (10q)
  UPDATE curriculum_lessons
    SET quiz_questions = '[{"id":"hs1-1","options":["Burner ignites → inducer starts → blower starts","Thermostat calls → inducer starts → pressure switch closes → igniter heats → gas valve opens → blower starts","Blower starts → gas valve opens → igniter heats","Gas valve opens → thermostat calls → inducer starts"],"question":"What is the correct startup sequence of a modern gas furnace?","explanation":"Thermostat calls → inducer starts → pressure switch closes → igniter heats → gas valve opens → burner lights → blower starts after heat exchanger warms.","correctAnswer":1},{"id":"hs1-2","options":["Circulate conditioned air through ducts","Establish draft through the heat exchanger before ignition","Ignite the gas burner","Regulate gas pressure to the burner"],"question":"What is the purpose of the inducer motor in a gas furnace?","explanation":"The inducer creates negative pressure to pull combustion gases through the heat exchanger and out the flue before ignition.","correctAnswer":1},{"id":"hs1-3","options":["Gas pressure is correct","Inducer has established proper draft","Heat exchanger is at operating temperature","Blower motor is running"],"question":"What does the pressure switch on a gas furnace verify?","explanation":"The pressure switch confirms the inducer has created sufficient negative pressure (draft) before allowing the gas valve to open.","correctAnswer":1},{"id":"hs1-4","options":["Low efficiency — causes high energy bills","A breach that allows combustion gases including CO to enter the airstream","Too small for the system","Scale buildup reducing heat transfer"],"question":"What is a cracked heat exchanger and why is it dangerous?","explanation":"A cracked heat exchanger allows CO — odorless and potentially fatal — to mix with circulating air. This is a red-tag condition requiring immediate shutdown.","correctAnswer":1},{"id":"hs1-5","options":["Reverse refrigerant flow to switch between heating and cooling modes","Reverse compressor rotation","Switch between high and low refrigerant charge","Bypass the metering device in heating mode"],"question":"What is the purpose of a heat pump reversing valve?","explanation":"The reversing valve switches refrigerant flow direction, allowing the heat pump to use the outdoor coil as evaporator (cooling) or condenser (heating).","correctAnswer":0},{"id":"hs1-6","options":["50°F (10°C)","35–40°F (2–4°C)","25°F (-4°C)","15°F (-9°C)"],"question":"At what outdoor temperature does a heat pump typically need auxiliary heat?","explanation":"Heat pump efficiency drops significantly below 35–40°F. At this balance point, auxiliary strip heat supplements or takes over.","correctAnswer":1},{"id":"hs1-7","options":["Radiant heat","Convective heat from resistance heating elements","Heat transferred from outdoor air","Heat from combustion of natural gas"],"question":"What type of heat does an electric heat strip produce?","explanation":"Electric heat strips use resistance heating elements — current through high-resistance wire generates heat. 100% efficient but expensive to operate.","correctAnswer":1},{"id":"hs1-8","options":["Refrigerant charge in a heat pump","Efficiency and safety of a gas combustion appliance","Airflow through supply registers","Electrical current draw of a furnace blower"],"question":"What is combustion analysis used to measure?","explanation":"Combustion analysis measures flue gas composition (CO, CO2, O2) and temperature to calculate efficiency and detect unsafe combustion.","correctAnswer":1},{"id":"hs1-9","options":["Limit gas pressure to the burner","Shut off the burner if the heat exchanger overheats","Limit blower speed","Prevent the thermostat from calling too frequently"],"question":"What is the purpose of a furnace limit switch?","explanation":"The limit switch opens and shuts off the gas valve if supply air temperature exceeds a safe threshold, preventing heat exchanger damage.","correctAnswer":1},{"id":"hs1-10","options":["Airflow capacity in CFM","Annual Fuel Utilization Efficiency — percentage of fuel converted to usable heat","Amperage draw of the blower motor","Maximum BTU output of the burner"],"question":"What does AFUE measure?","explanation":"AFUE measures how efficiently a furnace converts fuel to heat over a year. 96% AFUE = 96 cents of every dollar of gas becomes heat.","correctAnswer":1}]'::jsonb
    WHERE program_id = prog_id AND lesson_slug = 'hvac-lesson-20';

  -- hvac-lesson-26: Cooling Systems Quiz + Cumulative Mastery (Modules 1-5) (10q)
  UPDATE curriculum_lessons
    SET quiz_questions = '[{"id":"cs1-1","options":["It condenses from vapor to liquid","It absorbs heat from the space and evaporates from liquid to vapor","It is compressed to high pressure","Its pressure is reduced by the metering device"],"question":"What happens to refrigerant in the evaporator?","explanation":"In the evaporator, low-pressure liquid refrigerant absorbs heat from the conditioned space and evaporates into vapor, producing the cooling effect.","correctAnswer":1},{"id":"cs1-2","options":["The temperature above the condensing temperature","The temperature of refrigerant vapor above its saturation temperature at a given pressure","The temperature of the compressor discharge line","The difference between indoor and outdoor temperature"],"question":"What is superheat in a refrigeration system?","explanation":"Superheat is the temperature of refrigerant vapor above its saturation (boiling) point at a given pressure. Measured on the suction line to verify proper charge.","correctAnswer":1},{"id":"cs1-3","options":["The temperature below the evaporating temperature","The temperature of liquid refrigerant below its saturation temperature at a given pressure","The temperature drop across the evaporator","The cooling effect of the expansion process"],"question":"What is subcooling?","explanation":"Subcooling is the temperature of liquid refrigerant below its saturation point at a given pressure. Measured at the liquid line to verify full liquid to the metering device.","correctAnswer":1},{"id":"cs1-4","options":["Overcharge of refrigerant","Low refrigerant charge or restriction in the system","Overfeeding TXV","Condenser fan failure"],"question":"What does high superheat with low suction pressure typically indicate?","explanation":"High superheat + low suction pressure = refrigerant starved evaporator. Common causes: low charge, restricted metering device, or low airflow across evaporator.","correctAnswer":1},{"id":"cs1-5","options":["Compressor → evaporator → metering device → condenser","Compressor → condenser → metering device → evaporator","Compressor → metering device → condenser → evaporator","Compressor → condenser → evaporator → metering device"],"question":"What is the refrigerant cycle order starting from the compressor?","explanation":"High-pressure hot vapor leaves the compressor → condenser (rejects heat, becomes liquid) → metering device (reduces pressure) → evaporator (absorbs heat, becomes vapor) → back to compressor.","correctAnswer":1},{"id":"cs1-6","options":["CFC","HCFC","HFC — a zeotropic blend","Natural refrigerant"],"question":"What type of refrigerant is R-410A classified as?","explanation":"R-410A is an HFC (hydrofluorocarbon) zeotropic blend of R-32 and R-125. It has zero ozone depletion potential but high global warming potential.","correctAnswer":2},{"id":"cs1-7","options":["Mineral oil","Alkylbenzene oil","POE (polyolester) oil","PAG oil"],"question":"What oil is required for R-410A systems?","explanation":"R-410A requires POE (polyolester) oil. HFC refrigerants are not miscible with mineral or alkylbenzene oils used in older CFC/HCFC systems.","correctAnswer":2},{"id":"cs1-8","options":["Increase refrigerant pressure","Remove moisture and contaminants from the refrigerant","Measure refrigerant flow rate","Reduce refrigerant temperature"],"question":"What is the purpose of a filter-drier in a refrigeration system?","explanation":"The filter-drier removes moisture and particulate contaminants from the refrigerant circuit. Moisture causes acid formation and copper plating, damaging the compressor.","correctAnswer":1},{"id":"cs1-9","options":["System is properly charged","Low refrigerant charge or restriction upstream","Overcharge condition","Normal flash gas from the metering device"],"question":"What does a sight glass in a liquid line indicate when bubbling?","explanation":"Bubbles in the sight glass indicate flash gas — the liquid line pressure is too low to maintain full liquid. Causes: low charge, restriction, or excessive subcooling loss.","correctAnswer":1},{"id":"cs1-10","options":["The refrigerant charge efficiency","The cooling efficiency of an air conditioner over a typical cooling season","The heating efficiency of a heat pump","The airflow efficiency of a duct system"],"question":"What is the Seasonal Energy Efficiency Ratio (SEER) used to measure?","explanation":"SEER measures cooling output (BTU) divided by electrical energy input (Wh) over a typical cooling season. Higher SEER = more efficient system.","correctAnswer":1}]'::jsonb
    WHERE program_id = prog_id AND lesson_slug = 'hvac-lesson-26';

  -- hvac-lesson-34: EPA 608 Core Practice Exam (25q)
  UPDATE curriculum_lessons
    SET quiz_questions = '[{"id":"core1-1","options":["Regulate HVAC equipment efficiency","Phase out ozone-depleting substances including CFCs and HCFCs","Set refrigerant safety classifications","Establish technician certification requirements"],"question":"What is the primary purpose of the Montreal Protocol?","explanation":"The Montreal Protocol (1987) is an international treaty to phase out ozone-depleting substances. CFCs were phased out first; HCFCs (including R-22) are being phased out under its provisions.","correctAnswer":1},{"id":"core1-2","options":["HFCs","HCFCs","CFCs","Natural refrigerants"],"question":"Which refrigerant classification has the highest Ozone Depletion Potential (ODP)?","explanation":"CFCs (chlorofluorocarbons) like R-11 and R-12 have the highest ODP. They release chlorine in the stratosphere, destroying ozone molecules.","correctAnswer":2},{"id":"core1-3","options":["$1,000","$10,000","$44,539","$100,000"],"question":"Under Section 608 of the Clean Air Act, what is the maximum fine per day per violation for knowingly venting refrigerant?","explanation":"The EPA can impose fines up to $44,539 per day per violation for knowingly venting refrigerants. The amount is periodically adjusted for inflation.","correctAnswer":2},{"id":"core1-4","options":["A state HVAC license","EPA 608 certification","Both a state license and EPA 608 certification","No certification is required"],"question":"What must a technician have before purchasing refrigerant in containers larger than 2 lbs?","explanation":"EPA 608 certification is required to purchase refrigerant in containers larger than 2 lbs. Technicians must show proof of certification to refrigerant distributors.","correctAnswer":1},{"id":"core1-5","options":["Recycling refrigerant on-site for reuse","Removing refrigerant from a system and storing it in an external container","Reclaiming refrigerant to ARI 700 purity standards","Venting refrigerant safely to the atmosphere"],"question":"What does ''recovery'' mean under EPA 608?","explanation":"Recovery means removing refrigerant from a system and storing it in an approved external container. The refrigerant is NOT processed — it may be contaminated.","correctAnswer":1},{"id":"core1-6","options":["They are the same process","Recycling cleans refrigerant on-site for reuse in the same system; reclamation reprocesses to ARI 700 purity at an approved facility","Reclamation is done on-site; recycling is done at a facility","Recycling is for CFCs only; reclamation is for HFCs only"],"question":"What is the difference between recycling and reclamation?","explanation":"Recycling: cleaned on-site with recovery/recycling equipment for reuse in the same or similar system. Reclamation: sent to an EPA-certified facility and reprocessed to ARI 700 virgin purity standards.","correctAnswer":1},{"id":"core1-7","options":["Green","Blue","Gray body with yellow top","All yellow"],"question":"What color are refrigerant recovery cylinders required to be?","explanation":"Recovery cylinders must be gray with a yellow top per DOT regulations. This distinguishes them from new refrigerant cylinders and prevents mixing.","correctAnswer":2},{"id":"core1-8","options":["100% of capacity","90% of capacity","80% of water capacity","60% of water capacity"],"question":"What is the maximum fill level for a recovery cylinder?","explanation":"Recovery cylinders must not be filled beyond 80% of their water capacity to allow for liquid expansion. Overfilling creates a hydrostatic pressure hazard.","correctAnswer":2},{"id":"core1-9","options":["EPA","ASHRAE","ARI/AHRI","DOT"],"question":"Which organization certifies refrigerant reclaimers?","explanation":"The Air-Conditioning, Heating, and Refrigeration Institute (AHRI, formerly ARI) certifies refrigerant reclaimers. Reclaimed refrigerant must meet ARI 700 purity standards.","correctAnswer":2},{"id":"core1-10","options":["Never — all venting is illegal","Only for small amounts under 1 lb","Only for nitrogen and other non-ozone-depleting substances used for pressure testing","Only when the system is being permanently retired"],"question":"When is it legal to intentionally vent refrigerant?","explanation":"Intentional venting of refrigerants is illegal. Nitrogen and other non-ozone-depleting, non-HFC substances used for pressure testing may be vented. De minimis releases during good-faith recovery are not violations.","correctAnswer":2},{"id":"core1-11","options":["A1","A2L","A3","B1"],"question":"What is the ASHRAE 34 safety classification for R-410A?","explanation":"R-410A is classified A1 — low toxicity (A) and non-flammable (1). A1 is the safest classification under ASHRAE 34.","correctAnswer":0},{"id":"core1-12","options":["No records required","Name and address of purchaser and certification number","Only the quantity purchased","Only the type of refrigerant purchased"],"question":"What records must be kept when purchasing refrigerant?","explanation":"Refrigerant distributors must verify and record the purchaser''s EPA 608 certification number, name, and address for containers larger than 2 lbs.","correctAnswer":1},{"id":"core1-13","options":["Recover refrigerant from a system","Remove moisture and non-condensables from a system before charging","Measure refrigerant pressure","Circulate refrigerant during leak testing"],"question":"What is the purpose of a vacuum pump in HVAC service?","explanation":"A vacuum pump removes air, moisture, and non-condensables from a system before charging. Moisture left in the system causes acid formation and compressor damage.","correctAnswer":1},{"id":"core1-14","options":["500 microns or lower","1000 microns or lower","29 inches Hg","0 psig"],"question":"What vacuum level must be achieved before charging a system?","explanation":"Industry standard requires achieving 500 microns (0.5 mm Hg) or lower before charging. Some manufacturers require 300 microns. This ensures moisture removal.","correctAnswer":0},{"id":"core1-15","options":["0","1","1,810","3,990"],"question":"What is the Global Warming Potential (GWP) of R-22 relative to CO2?","explanation":"R-22 has a GWP of approximately 1,810 — meaning it traps 1,810 times more heat than CO2 over 100 years. This is why HFCs with lower GWP are being developed as replacements.","correctAnswer":2},{"id":"core1-16","options":["Skin burns from cold contact","Oxygen displacement leading to asphyxiation","Toxic fume inhalation","Explosion risk"],"question":"What is the primary health hazard of refrigerant exposure in an enclosed space?","explanation":"Refrigerants are heavier than air and displace oxygen in enclosed spaces. High concentrations cause asphyxiation. Always ventilate before working in confined spaces with refrigerant.","correctAnswer":1},{"id":"core1-17","options":["The temperature at which a refrigerant freezes","The temperature at which a refrigerant boils or condenses at a given pressure","The maximum safe operating temperature","The temperature of the refrigerant leaving the compressor"],"question":"What does the term ''saturation temperature'' mean?","explanation":"Saturation temperature is the temperature at which a refrigerant changes state (boils or condenses) at a specific pressure. This is the basis of the P-T chart.","correctAnswer":1},{"id":"core1-18","options":["EPA 608","ARI 740","ASHRAE 15","DOT 49 CFR"],"question":"What standard certifies refrigerant recovery equipment?","explanation":"ARI Standard 740 (now AHRI 740) establishes performance testing requirements for refrigerant recovery and recycling equipment. Equipment must be certified to this standard.","correctAnswer":1},{"id":"core1-19","options":["R-22","R-134a","R-410A","R-12"],"question":"Which refrigerant is a near-azeotropic blend that must be charged as a liquid?","explanation":"R-410A is a near-azeotropic blend (R-32/R-125). It must be charged as a liquid from the cylinder to prevent fractionation — the components have different vapor pressures and would separate if charged as vapor.","correctAnswer":2},{"id":"core1-20","options":["Nothing — just open the service valves","Recover all refrigerant from the system","Add nitrogen to pressurize the system","Flush the system with water"],"question":"What must be done before opening a system for repair?","explanation":"All refrigerant must be recovered before opening a system. Releasing refrigerant to the atmosphere is illegal under Section 608 of the Clean Air Act.","correctAnswer":1},{"id":"core1-21","options":["Increase refrigerant pressure","Remove moisture and contaminants from the refrigerant circuit","Measure refrigerant flow rate","Reduce refrigerant temperature"],"question":"What is the function of a filter-drier?","explanation":"The filter-drier removes moisture and particulate contaminants. Moisture causes acid formation and copper plating, damaging the compressor.","correctAnswer":1},{"id":"core1-22","options":["CFC","HCFC","HFC","Natural"],"question":"R-22 is classified as which type of refrigerant?","explanation":"R-22 (chlorodifluoromethane) is an HCFC — hydrochlorofluorocarbon. It has lower ODP than CFCs but still depletes ozone. Production for new equipment ended in 2010; production ended entirely in 2020.","correctAnswer":1},{"id":"core1-23","options":["-41°F (-41°C)","-15°F (-26°C)","32°F (0°C)","14°F (-10°C)"],"question":"What is the boiling point of R-134a at atmospheric pressure?","explanation":"R-134a boils at approximately -15°F (-26°C) at atmospheric pressure. This low boiling point allows it to absorb heat from spaces above that temperature.","correctAnswer":1},{"id":"core1-24","options":["Blue","Green","Red","Yellow"],"question":"Which gauge color indicates the high-pressure (discharge) side?","explanation":"Red = high-pressure (discharge) side. Blue = low-pressure (suction) side. This is a universal color convention for manifold gauge sets.","correctAnswer":2},{"id":"core1-25","options":["Add the correct refrigerant on top","Recover all refrigerant, identify the mixture, and dispose of it properly — do not reuse","Vent the system and recharge","Add oil to dilute the wrong refrigerant"],"question":"What should you do if you discover a system has been charged with the wrong refrigerant?","explanation":"Mixed refrigerants cannot be reclaimed to ARI 700 standards and must be disposed of properly. Never add refrigerant on top of an unknown mixture — it contaminates recovery cylinders.","correctAnswer":1}]'::jsonb
    WHERE program_id = prog_id AND lesson_slug = 'hvac-lesson-34';

  -- hvac-lesson-4: Orientation Quiz (10q)
  UPDATE curriculum_lessons
    SET quiz_questions = '[{"id":"o1-1","options":["8 weeks","12 weeks","16 weeks","24 weeks"],"question":"How long is the Elevate HVAC Technician Training Program?","explanation":"The program is 16 weeks covering HVAC fundamentals through EPA 608 prep and career readiness.","correctAnswer":2},{"id":"o1-2","options":["OSHA 10","EPA 608 Universal","NATE Core","CompTIA A+"],"question":"What certification does this program prepare you to take?","explanation":"EPA 608 Universal is required by federal law to purchase and handle refrigerants.","correctAnswer":1},{"id":"o1-3","options":["60%","65%","70%","80%"],"question":"What is the minimum passing score on checkpoint exams?","explanation":"70% matches the real EPA 608 exam standard.","correctAnswer":2},{"id":"o1-4","options":["OSHA Act of 1970","Clean Air Act Section 608","DOT Hazardous Materials Regulations","ASHRAE Standard 34"],"question":"Which federal law requires HVAC technicians to be certified before purchasing refrigerants?","explanation":"Section 608 of the Clean Air Act requires certification for anyone servicing refrigerant-containing appliances.","correctAnswer":1},{"id":"o1-5","options":["Workforce Investment and Opportunity Act","Workforce Innovation and Opportunity Act","Worker Income and Occupational Assistance","Workforce Integration and Outreach Agency"],"question":"What does WIOA stand for?","explanation":"WIOA — Workforce Innovation and Opportunity Act — funds workforce development programs including Elevate.","correctAnswer":1},{"id":"o1-6","options":["None","Transportation, childcare, and work supplies","Federal student loan deferment only","State unemployment benefits"],"question":"Which support services are available to WIOA-funded participants?","explanation":"WIOA wraparound services include transportation, childcare, tools, and other barrier-removal assistance.","correctAnswer":1},{"id":"o1-7","options":["EPA Training and Permit License","Eligible Training Provider List","Employment and Technical Program Listing","Elevate Training Program License"],"question":"What does ETPL stand for?","explanation":"ETPL — Eligible Training Provider List — programs on this list can receive WIOA funding.","correctAnswer":1},{"id":"o1-8","options":["Licensed electrician","Entry-level HVAC technician with EPA 608 certification","Two-year associate degree","Certified building inspector"],"question":"What is the primary career outcome of completing this program?","explanation":"Graduates are prepared for entry-level HVAC roles with EPA 608 Universal certification.","correctAnswer":1},{"id":"o1-9","options":["Nothing — attendance is optional","Loss of WIOA funding and program standing","Automatic incomplete grade","Moved to next cohort without penalty"],"question":"What can happen if a learner misses more than the allowed sessions?","explanation":"Attendance is tied to WIOA compliance. Excessive absences can result in loss of funding.","correctAnswer":1},{"id":"o1-10","options":["Refrigerant Handling and Safety","EPA 608 Certification Prep","Automotive Engine Repair","System Diagnostics and Troubleshooting"],"question":"Which topic is NOT covered in this HVAC program?","explanation":"Automotive engine repair is not part of the HVAC curriculum.","correctAnswer":2}]'::jsonb
    WHERE program_id = prog_id AND lesson_slug = 'hvac-lesson-4';

  -- hvac-lesson-76: Troubleshooting Quiz + Cumulative Mastery (Modules 1-13) (10q)
  UPDATE curriculum_lessons
    SET quiz_questions = '[{"id":"ts1-1","options":["Replace the most likely failed component","Gather information — talk to the customer and observe symptoms","Check refrigerant pressures immediately","Pull the disconnect and inspect wiring"],"question":"What is the first step in a systematic HVAC troubleshooting approach?","explanation":"Always start by gathering information: talk to the customer about symptoms, when the problem started, and any recent changes. Check thermostat settings. Many calls are resolved at this step.","correctAnswer":1},{"id":"ts1-2","options":["Low refrigerant charge","Overcharge or overfeeding metering device","Restricted liquid line","Compressor valve failure"],"question":"High suction pressure and low superheat typically indicate what condition?","explanation":"High suction pressure + low superheat = too much refrigerant entering the evaporator. Causes: overcharge, TXV stuck open, or oversized metering device.","correctAnswer":1},{"id":"ts1-3","options":["Overcharge","Condenser fan failure","Low refrigerant charge or restriction","Compressor short cycling"],"question":"Low suction pressure and high superheat indicate what condition?","explanation":"Low suction pressure + high superheat = refrigerant-starved evaporator. Causes: low charge, restricted metering device, restricted filter-drier, or low airflow across evaporator.","correctAnswer":2},{"id":"ts1-4","options":["Low refrigerant charge","Condenser problem — dirty coil, failed fan, or non-condensables in system","Evaporator icing","Compressor valve failure"],"question":"High head pressure with normal suction pressure suggests what?","explanation":"High head pressure with normal suction = condenser cannot reject heat efficiently. Check: dirty condenser coil, failed condenser fan motor, blocked airflow, or air/non-condensables in system.","correctAnswer":1},{"id":"ts1-5","options":["Overcharge","Compressor valve failure — not pumping efficiently","Low refrigerant charge","Restricted metering device"],"question":"Low head pressure and low suction pressure with low superheat typically indicates?","explanation":"Low head and low suction with low superheat = compressor not pumping. Worn or broken compressor valves allow refrigerant to bypass, reducing compression ratio.","correctAnswer":1},{"id":"ts1-6","options":["Refrigerant charge","Thermostat settings and air filter","Compressor amperage","Condenser coil cleanliness"],"question":"What is the first thing to check when a system runs but does not cool?","explanation":"Always check the simple things first: thermostat set correctly, air filter not clogged, supply registers open. A dirty filter is one of the most common causes of poor cooling.","correctAnswer":1},{"id":"ts1-7","options":["Failed inducer motor","Flame sensor dirty or failed — cannot prove flame to the control board","Cracked heat exchanger","Failed pressure switch"],"question":"A gas furnace ignites but shuts off after a few seconds. What is the most likely cause?","explanation":"If the burner lights then shuts off within seconds, the flame sensor is not detecting the flame. A dirty or failed flame sensor is the most common cause of this symptom.","correctAnswer":1},{"id":"ts1-8","options":["System is properly charged","Flash gas — low charge or restriction upstream of sight glass","Overcharge condition","Normal operation at high ambient temperature"],"question":"What does a bubbling sight glass in the liquid line indicate?","explanation":"Bubbles in the sight glass indicate flash gas — liquid refrigerant is flashing before the metering device. Causes: low charge, restriction, or excessive pressure drop in liquid line.","correctAnswer":1},{"id":"ts1-9","options":["Superheat method","Subcooling method","Weigh-in method only","Either superheat or subcooling — both work equally"],"question":"What is the proper method for measuring refrigerant charge on a fixed-orifice system?","explanation":"Fixed-orifice systems (cap tube, piston) use the superheat method. TXV/EXV systems use the subcooling method. Using the wrong method gives incorrect charge readings.","correctAnswer":0},{"id":"ts1-10","options":["Fix it without telling the customer to avoid alarm","Clearly explain the safety hazard, document it in writing, and do not restart the equipment","Restart the equipment and schedule a follow-up","Only report it if the customer asks"],"question":"How should a technician communicate a red-tag condition to a customer?","explanation":"A red-tag condition (cracked heat exchanger, gas leak, electrical hazard) must be clearly communicated in writing. The equipment must not be restarted until repaired. This protects the customer and the technician legally.","correctAnswer":1}]'::jsonb
    WHERE program_id = prog_id AND lesson_slug = 'hvac-lesson-76';

  -- hvac-lesson-87: CPR Skills Assessment (10q)
  UPDATE curriculum_lessons
    SET quiz_questions = '[{"id":"cpr1-1","options":["1 inch","At least 2 inches but no more than 2.4 inches","3 inches","As deep as possible"],"question":"What is the correct compression depth for adult CPR?","explanation":"AHA guidelines: compress at least 2 inches (5 cm) but no more than 2.4 inches (6 cm) for adults. Too shallow is ineffective; too deep causes injury.","correctAnswer":1},{"id":"cpr1-2","options":["60–80 compressions per minute","80–100 compressions per minute","100–120 compressions per minute","120–140 compressions per minute"],"question":"What is the correct compression rate for CPR?","explanation":"The AHA recommends 100–120 compressions per minute for all ages. The song ''Stayin'' Alive'' by the Bee Gees is approximately 100 BPM — a useful memory aid.","correctAnswer":2},{"id":"cpr1-3","options":["15:2","30:2","50:2","Compressions only — no ventilations"],"question":"What is the compression-to-ventilation ratio for single-rescuer adult CPR?","explanation":"30 compressions to 2 rescue breaths for single-rescuer adult CPR. For two trained rescuers, the ratio remains 30:2 until an advanced airway is placed.","correctAnswer":1},{"id":"cpr1-4","options":["Only after 10 minutes of CPR","As soon as it is available — attach and use immediately","Only by medical professionals","Only if the victim is conscious"],"question":"When should an AED be used?","explanation":"Attach and use an AED as soon as it is available. Every minute without defibrillation reduces survival by 7–10%. CPR buys time; defibrillation restores rhythm.","correctAnswer":1},{"id":"cpr1-5","options":["Check for a pulse for 60 seconds","Resume CPR immediately starting with chest compressions","Wait for the AED to reanalyze","Call 911 before continuing"],"question":"What should you do immediately after delivering an AED shock?","explanation":"Resume CPR immediately after a shock — start with chest compressions. Do not pause to check for a pulse. The AED will prompt reanalysis after 2 minutes of CPR.","correctAnswer":1},{"id":"cpr1-6","options":["On the upper chest near the collarbone","Heel of one hand on the center of the chest (lower half of sternum), other hand on top","On the left side of the chest over the heart","On the abdomen below the sternum"],"question":"What is the correct hand placement for adult chest compressions?","explanation":"Place the heel of one hand on the center of the chest (lower half of the sternum), interlock fingers of the other hand on top. Keep fingers off the chest wall.","correctAnswer":1},{"id":"cpr1-7","options":["Automated Emergency Defibrillator","Automated External Defibrillator","Automatic Electrical Device","Advanced Emergency Device"],"question":"What does AED stand for?","explanation":"AED — Automated External Defibrillator. It analyzes heart rhythm and delivers a shock if a shockable rhythm (VF or pulseless VT) is detected.","correctAnswer":1},{"id":"cpr1-8","options":["Begin chest compressions immediately","Check for responsiveness, call 911 (or have someone call), then begin CPR","Give 2 rescue breaths first","Attach the AED before doing anything else"],"question":"What is the first step when you find an unresponsive person?","explanation":"Check for responsiveness (tap shoulders, shout). If unresponsive and not breathing normally, call 911 (or direct someone to call), then begin CPR. Time to first compression matters.","correctAnswer":1},{"id":"cpr1-9","options":["Blow as hard as possible for 3 seconds each","Give each breath over 1 second — just enough to see the chest rise","Give 5 rapid breaths before starting compressions","Breaths are not recommended — compressions only"],"question":"How should rescue breaths be delivered during CPR?","explanation":"Each rescue breath should be delivered over 1 second with just enough volume to see the chest rise. Over-ventilation causes gastric inflation and reduces venous return.","correctAnswer":1},{"id":"cpr1-10","options":["To give the rescuer time to rest","To allow the heart to refill with blood between compressions","To prevent rib fractures","To maintain the correct compression rate"],"question":"What is the purpose of allowing full chest recoil between compressions?","explanation":"Full chest recoil allows the heart to refill with blood between compressions, maximizing cardiac output. Leaning on the chest between compressions reduces effectiveness.","correctAnswer":1}]'::jsonb
    WHERE program_id = prog_id AND lesson_slug = 'hvac-lesson-87';

  -- hvac-lesson-9: HVAC Fundamentals Quiz (10q)
  UPDATE curriculum_lessons
    SET quiz_questions = '[{"id":"hf1-1","options":["Compressor, condenser, metering device, evaporator","Compressor, filter, blower, thermostat","Condenser, expansion tank, pump, evaporator","Blower, heat exchanger, burner, flue"],"question":"What are the four main components of a basic refrigeration cycle?","explanation":"Compressor pressurizes vapor → condenser rejects heat → metering device reduces pressure → evaporator absorbs heat.","correctAnswer":0},{"id":"hf1-2","options":["Removes heat from refrigerant","Increases pressure and temperature of refrigerant vapor","Reduces refrigerant pressure to cause cooling","Filters moisture from refrigerant"],"question":"What does the compressor do in a refrigeration system?","explanation":"The compressor raises pressure and temperature of low-pressure vapor, moving it to the high-pressure side.","correctAnswer":1},{"id":"hf1-3","options":["Evaporator","Metering device","Compressor","Condenser"],"question":"Where does heat rejection occur in a refrigeration system?","explanation":"The condenser rejects heat from refrigerant to outside air or water, condensing high-pressure vapor into liquid.","correctAnswer":3},{"id":"hf1-4","options":["Compress refrigerant vapor","Filter contaminants","Reduce refrigerant pressure and control flow into the evaporator","Measure refrigerant charge by weight"],"question":"What is the purpose of the metering device?","explanation":"The metering device (TXV, cap tube, or fixed orifice) reduces pressure, causing refrigerant to flash and cool.","correctAnswer":2},{"id":"hf1-5","options":["Sensible heat changes temperature; latent heat changes state without changing temperature","Latent heat changes temperature; sensible heat changes state","They are the same thing","Sensible heat applies only to gases; latent heat only to liquids"],"question":"What is the difference between sensible heat and latent heat?","explanation":"Sensible heat causes a measurable temperature change. Latent heat is absorbed or released during a state change with no temperature change.","correctAnswer":0},{"id":"hf1-6","options":["Multimeter","Manifold gauge set","Micron gauge","Clamp meter"],"question":"What tool measures both high-side and low-side refrigerant pressures simultaneously?","explanation":"A manifold gauge set has high-side (red) and low-side (blue) gauges plus a center port for recovery, charging, or evacuation.","correctAnswer":1},{"id":"hf1-7","options":["Heating, Ventilation, Air Conditioning, Refrigeration","High Voltage Alternating Current Relay","Heating, Venting, Airflow, Cooling, Recovery","Humidity, Ventilation, Air Circulation, Refrigerant"],"question":"What does HVACR stand for?","explanation":"HVACR — Heating, Ventilation, Air Conditioning, and Refrigeration — is the full scope of the trade.","correctAnswer":0},{"id":"hf1-8","options":["Calculate electrical load","Determine saturation temperature of a refrigerant at a given pressure","Measure airflow in ducts","Size equipment for a space"],"question":"What is the purpose of a pressure-temperature (P-T) chart?","explanation":"A P-T chart shows the relationship between pressure and saturation temperature for specific refrigerants.","correctAnswer":1},{"id":"hf1-9","options":["Safety glasses only","Safety glasses and insulated gloves","Safety glasses, chemical-resistant gloves, and closed-toe shoes","No PPE required for small systems"],"question":"What minimum PPE is required when working with refrigerants?","explanation":"Minimum PPE: safety glasses or goggles, chemical-resistant gloves, and closed-toe shoes. Refrigerants cause frostbite and eye injury.","correctAnswer":2},{"id":"hf1-10","options":["P-T chart","Wiring diagram (schematic)","Manifold gauge set","Equipment nameplate"],"question":"Which component shows electrical connections between HVAC components for troubleshooting?","explanation":"Wiring diagrams show circuit logic and electrical connections essential for diagnosing electrical faults.","correctAnswer":1}]'::jsonb
    WHERE program_id = prog_id AND lesson_slug = 'hvac-lesson-9';

END $$;
